def forward_step(data_iterator, model: GPTModel):
    """Forward training step.

    Args:
        data_iterator: Data iterator.
        model: GPT model object.

    Returns:
        Model output tensor and partially applied loss function.
    """
    # Get a batch from the data iterator
    batch = next(data_iterator)

    # Move batch to GPU if needed
    if torch.cuda.is_available():
        batch = {k: v.cuda() if isinstance(v, torch.Tensor) else v for k, v in batch.items()}

    # Forward pass through the model
    output = model(**batch)

    # Prepare loss function
    def loss_func(output):
        # Compute loss based on model configuration
        if hasattr(model, 'distillation') and model.distillation:
            # Distillation mode: pass model info for teacher guidance
            return model.compute_distillation_loss(output, batch)
        else:
            return model.compute_loss(output, batch)

    return output, loss_func
